    "accounts"  => '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"/>',
    "users"     => '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z"/>',
    "leads"     => '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z"/>',
    "stores"    => '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 100 4 2 2 0 000-4z"/>',
    "sites"     => '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9"/>'
  }.freeze

  def admin_nav_link(label, path, key)
    active = request.path.start_with?(path) || (key == "dashboard" && request.path == admin_root_path)
    icon_path = ADMIN_NAV_ICONS[key]

    link_to path, class: "flex items-center gap-3 px-3 py-2 text-sm rounded-lg transition-colors #{active ? 'font-semibold text-brand-highlight dark:text-cyan-400 bg-brand-highlight/10 dark:bg-cyan-500/10' : 'text-brand-text-muted dark:text-slate-400 hover:text-brand-highlight dark:hover:text-cyan-400 hover:bg-brand-card-alt dark:hover:bg-slate-800'}" do
      raw("<svg class='w-5 h-5' fill='none' stroke='currentColor' viewBox='0 0 24 24'>#{icon_path}</svg>") +
        content_tag(:span, label)
    end
  end
end
